/**
 * Deep Link Handler for custom scheme myapp://
 * Handles URLs like:
 *   myapp://profile/123
 *   myapp://payment/confirm
 *
 * Security measures:
 * - Validates scheme
 * - Sanitizes path parameters
 * - Whitelist-based route matching
 * - Input validation for IDs
 * - No arbitrary Activity launching
 */

// Data class to represent a parsed deep link
data class DeepLinkResult(
    val route: DeepLinkRoute,
    val params: Map<String, String> = emptyMap()
)

// Enum of allowed routes (whitelist approach)
enum class DeepLinkRoute {
    PROFILE,
    PAYMENT_CONFIRM,
    UNKNOWN
}

/**
 * Secure Deep Link Parser
 */
object DeepLinkParser {

    private const val TAG = "DeepLinkParser"
    private const val VALID_SCHEME = "myapp"
    private val ALPHANUMERIC_REGEX = Regex("^[a-zA-Z0-9_-]+$")

    /**
     * Parse and validate a deep link URI.
     * Returns null if the URI is invalid or potentially malicious.
     */
    fun parse(uri: Uri?): DeepLinkResult? {
        if (uri == null) {
            Log.w(TAG, "Received null URI")
            return null
        }

        // Validate scheme
        if (!isValidScheme(uri.scheme)) {
            Log.w(TAG, "Invalid scheme: ${uri.scheme}")
            return null
        }

        // Validate host is not null/empty
        val host = uri.host
        if (host.isNullOrBlank()) {
            Log.w(TAG, "Missing host in deep link")
            return null
        }

        // Prevent path traversal attacks
        val fullPath = uri.path?.replace("..", "") ?: ""
        if (fullPath.contains("..") || fullPath.contains("//")) {
            Log.w(TAG, "Potential path traversal detected: $fullPath")
            return null
        }

        val pathSegments = uri.pathSegments?.map { sanitize(it) } ?: emptyList()

        return when (host.lowercase()) {
            "profile" -> parseProfileLink(pathSegments)
            "payment" -> parsePaymentLink(pathSegments)
            else -> {
                Log.w(TAG, "Unknown deep link host: $host")
                null
            }
        }
    }

    private fun parseProfileLink(pathSegments: List<String>): DeepLinkResult? {
        if (pathSegments.isEmpty()) {
            Log.w(TAG, "Profile deep link missing user ID")
            return null
        }

        val userId = pathSegments[0]

        // Validate user ID is alphanumeric
        if (!isValidId(userId)) {
            Log.w(TAG, "Invalid profile ID: $userId")
            return null
        }

        return DeepLinkResult(
            route = DeepLinkRoute.PROFILE,
            params = mapOf("userId" to userId)
        )
    }

    private fun parsePaymentLink(pathSegments: List<String>): DeepLinkResult? {
        if (pathSegments.isEmpty()) {
            Log.w(TAG, "Payment deep link missing action")
            return null
        }

        return when (pathSegments[0].lowercase()) {
            "confirm" -> DeepLinkResult(
                route = DeepLinkRoute.PAYMENT_CONFIRM,
                params = emptyMap()
            )
            else -> {
                Log.w(TAG, "Unknown payment action: ${pathSegments[0]}")
                null
            }
        }
    }

    private fun isValidScheme(scheme: String?): Boolean {
        return scheme?.lowercase() == VALID_SCHEME
    }

    private fun isValidId(id: String): Boolean {
        // Only allow alphanumeric IDs with reasonable length
        return id.length in 1..64 && ALPHANUMERIC_REGEX.matches(id)
    }

    private fun sanitize(input: String): String {
        // Remove any potentially dangerous characters
        return input.replace(Regex("[^a-zA-Z0-9_-]"), "")
    }
}

/**
 * Navigator that routes parsed deep links to the appropriate Activity.
 * Uses a whitelist approach — only known routes are handled.
 */
object DeepLinkNavigator {

    private const val TAG = "DeepLinkNavigator"

    fun navigate(activity: Activity, result: DeepLinkResult): Boolean {
        val intent = when (result.route) {
            DeepLinkRoute.PROFILE -> {
                Intent(activity, ProfileActivity::class.java).apply {
                    putExtra(ProfileActivity.EXTRA_USER_ID, result.params["userId"])
                    // Prevent this intent from being intercepted
                    setPackage(activity.packageName)
                }
            }
            DeepLinkRoute.PAYMENT_CONFIRM -> {
                Intent(activity, PaymentConfirmActivity::class.java).apply {
                    setPackage(activity.packageName)
                }
            }
            DeepLinkRoute.UNKNOWN -> {
                Log.w(TAG, "Cannot navigate to unknown route")
                return false
            }
        }

        // Security: ensure the intent resolves to our own app
        intent.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_SINGLE_TOP)

        return try {
            activity.startActivity(intent)
            true
        } catch (e: Exception) {
            Log.e(TAG, "Failed to navigate: ${e.message}")
            false
        }
    }
}

/**
 * Entry point Activity that handles all deep links.
 * Declared in AndroidManifest.xml with intent-filter for myapp:// scheme.
 *
 * AndroidManifest.xml should include:
 *
 * <activity
 *     android:name=".DeepLinkHandlerActivity"
 *     android:exported="true"
 *     android:launchMode="singleTask">
 *     <intent-filter>
 *         <action android:name="android.intent.action.VIEW" />
 *         <category android:name="android.intent.category.DEFAULT" />
 *         <category android:name="android.intent.category.BROWSABLE" />
 *         <data android:scheme="myapp" />
 *     </intent-filter>
 * </activity>
 */
class DeepLinkHandlerActivity : Activity() {

    companion object {
        private const val TAG = "DeepLinkHandler"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleIntent(it) }
    }

    private fun handleIntent(intent: Intent) {
        val uri = intent.data

        if (uri == null) {
            Log.w(TAG, "No URI in deep link intent")
            navigateToDefault()
            return
        }

        Log.d(TAG, "Handling deep link: $uri")

        // Validate referrer to prevent unauthorized deep link invocations
        if (!isValidReferrer()) {
            Log.w(TAG, "Deep link from untrusted referrer")
            // Still allow navigation but log for monitoring
        }

        val result = DeepLinkParser.parse(uri)

        if (result == null) {
            Log.w(TAG, "Failed to parse deep link: $uri")
            navigateToDefault()
            return
        }

        val navigated = DeepLinkNavigator.navigate(this, result)

        if (!navigated) {
            Log.w(TAG, "Failed to navigate for deep link: $uri")
            navigateToDefault()
        }

        finish()
    }

    private fun isValidReferrer(): Boolean {
        // On API 22+, check the referrer
        val referrer = referrer
        if (referrer != null) {
            val referrerPackage = referrer.host ?: return true
            // Allow our own app, system apps, and known trusted sources
            val trustedPackages = setOf(
                packageName,
                "com.google.android.gm",       // Gmail
                "com.google.android.apps.messaging", // Messages
                "com.android.chrome",           // Chrome
            )
            return referrerPackage in trustedPackages || referrerPackage.startsWith("com.android")
        }
        return true // No referrer info available, allow
    }

    private fun navigateToDefault() {
        // Navigate to main activity as fallback
        val intent = Intent(this, MainActivity::class.java).apply {
            setPackage(packageName)
            addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_NEW_TASK)
        }
        startActivity(intent)
        finish()
    }
}

